import pickle
import re
from flask import Flask, request, jsonify
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
import numpy as np

app = Flask(__name__)

# Load pre-trained model and vectorizer
try:
    with open('model.pkl', 'rb') as f:
        model = pickle.load(f)
    with open('vectorizer.pkl', 'rb') as f:
        vectorizer = pickle.load(f)
except FileNotFoundError:
    # Create dummy model for demonstration
    model = LogisticRegression()
    vectorizer = CountVectorizer(max_features=1000, stop_words='english')
    model.fit([["dummy"], ["spam"]], [0, 1])

def preprocess_text(text):
    """Clean and preprocess email text"""
    if not isinstance(text, str):
        return ""
    text = re.sub(r'[^a-zA-Z\s]', '', text)
    text = text.lower().strip()
    return text

def predict_spam_probability(email_text):
    """Predict spam probability for given email text"""
    try:
        processed_text = preprocess_text(email_text)
        if not processed_text:
            return 0.0
        
        # Transform text using pre-trained vectorizer
        text_vector = vectorizer.transform([processed_text])
        
        # Get prediction probability
        probability = model.predict_proba(text_vector)[0][1]  # Probability of spam class
        
        return float(probability)
    except Exception:
        return 0.0

@app.route('/predict', methods=['POST'])
def predict():
    """API endpoint to predict spam probability"""
    try:
        data = request.get_json()
        if not data or 'email_text' not in data:
            return jsonify({'error': 'Missing email_text in request'}), 400
        
        email_text = data['email_text']
        spam_probability = predict_spam_probability(email_text)
        
        return jsonify({
            'spam_probability': spam_probability,
            'is_spam': spam_probability > 0.5
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/health', methods=['GET'])
def health():
    """Health check endpoint"""
    return jsonify({'status': 'healthy'})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)